+//! Output rendering for human and robot modes.
+
+pub mod doctor;
+pub mod human;
+pub mod robot;
+
+use crate::cli::args::OutputFormat;
+use crate::core::doctor::DoctorReport;
+use crate::core::models::{CostPayload, ProviderPayload};
